def test__json_with_charset_utf16(client) -> None:
    """JSON with UTF-16 charset should be rejected (UTF-8 only)."""
    response = client.post(
        "/data",
        json={"value": "test"},
        headers={
            "Content-Type": "application/json; charset=utf-16",
        },
    )
    assert response.status_code == 415
    data = response.json()
    assert data == {"detail": "Unsupported charset 'utf-16' for JSON. Only UTF-8 is supported.", "status": 415, "title": "Unsupported Charset", "type": "https://spikard.dev/errors/unsupported-charset"}

